// ─── RESPONSIVE HOOK ──────────────────────────────────────────────────────────
function useBreakpoint() {
  const [w, setW] = useState(typeof window !== "undefined" ? window.innerWidth : 1200);
  useEffect(() => {
    const fn = () => setW(window.innerWidth);
    window.addEventListener("resize", fn);
    return () => window.removeEventListener("resize", fn);
  }, []);
  return { isMobile: w < 640, isTablet: w >= 640 && w < 1024, isDesktop: w >= 1024, w };
}

// ─── SEO UTILITIES ────────────────────────────────────────────────────────────
function useSEO({ title, description, keywords, canonical }) {
  useEffect(() => {
    const base = "The Treasures List";
    document.title = title ? `${title} | ${base}` : base;
    const setMeta = (name, content, prop = false) => {
      const sel = prop ? `meta[property="${name}"]` : `meta[name="${name}"]`;
      let el = document.querySelector(sel);
      if (!el) {
        el = document.createElement("meta");
        prop ? el.setAttribute("property", name) : el.setAttribute("name", name);
        document.head.appendChild(el);
      }
      el.setAttribute("content", content);
    };
    if (description) { setMeta("description", description); setMeta("og:description", description, true); }
    if (keywords)    setMeta("keywords", keywords);
    if (title)       setMeta("og:title", title + " | " + base, true);
    setMeta("og:type", "website", true);
    setMeta("og:site_name", base, true);
    if (canonical) {
      let link = document.querySelector("link[rel='canonical']");
      if (!link) { link = document.createElement("link"); link.setAttribute("rel", "canonical"); document.head.appendChild(link); }
      link.setAttribute("href", `https://thetreasureslist.com${canonical}`);
    }
  }, [title, description, keywords, canonical]);
}

function injectSchema(data) {
  const id = "tl-schema";
  let el = document.getElementById(id);
  if (!el) { el = document.createElement("script"); el.id = id; el.type = "application/ld+json"; document.head.appendChild(el); }
  el.textContent = JSON.stringify(data);
}

function buildSEO(mode, catId, city, state, catLabel) {
  if (catId === "all" && city === "all") {
    return {
      title: "Independent Business & Creator Directory",
      description: "The Treasures List — the definitive directory of independent businesses, artists, and creators worldwide. Skate shops, tattoo artists, record stores, dive bars, ceramics, leather goods, and more. No chains, no algorithms.",
      keywords: "independent businesses, skate shops, tattoo artists, dive bars, record stores, art galleries, surf shops, vintage thrift, small brands, ceramics, leather goods, independent directory",
    };
  }
  if (catId !== "all" && city !== "all") {
    return {
      title: `Best ${catLabel} in ${city}${state ? ", " + state : ""}`,
      description: `The best independent ${catLabel.toLowerCase()} in ${city} — curated by The Treasures List. Real spots, no chains, no algorithms.`,
      keywords: `${catLabel.toLowerCase()} ${city}, independent ${catLabel.toLowerCase()} ${city}, best ${catLabel.toLowerCase()} ${city} ${state || ""}`.trim(),
    };
  }
  if (catId !== "all") {
    return {
      title: `Best Independent ${catLabel} — Global Directory`,
      description: `Discover the world's best independent ${catLabel.toLowerCase()} — curated globally by The Treasures List.`,
      keywords: `best independent ${catLabel.toLowerCase()}, ${catLabel.toLowerCase()} directory, independent ${catLabel.toLowerCase()} worldwide`,
    };
  }
  if (city !== "all") {
    return {
      title: `Best Independent Businesses in ${city}${state ? ", " + state : ""}`,
      description: `The Treasures List guide to ${city} — curated independent businesses, artists, skate shops, tattoo artists, record stores, dive bars, galleries, and more.`,
      keywords: `independent businesses ${city}, best shops ${city}, skate shops ${city}, tattoo ${city}, dive bars ${city}, record stores ${city}`,
    };
  }
  return { title: "", description: "", keywords: "" };
}

